// Chat Message Component
export default function ChatMessageModal({ onClose }) {
    const [selectedUser, setSelectedUser] = useState(chatUsers[0]);
    const [messageInput, setMessageInput] = useState("");
    const [messages, setMessages] = useState(chatUsers);

    const handleSendMessage = () => {
        if (!messageInput.trim()) return;

        const newMessage = {
            id: messages.find(u => u.id === selectedUser.id)?.messages.length + 1 || 1,
            sender: "Me",
            text: messageInput,
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            isMe: true,
        };

        const updatedMessages = messages.map(user => {
            if (user.id === selectedUser.id) {
                return {
                    ...user,
                    messages: [...user.messages, newMessage],
                };
            }
            return user;
        });

        setMessages(updatedMessages);
        setMessageInput("");
    };

    const getStatusColor = (status) => {
        return status === "online" ? "#4caf50" : "#9e9e9e";
    };

    const getSenderTypeColor = (role) => {
        if (role === "Portfolio Company") return "#f44336";
        if (role === "Fellow Shareholder") return "#ffc107";
        if (role === "Angel Network Member") return "#4caf50";
        if (role === "Follower") return "#2196f3";
        if (role === "Admin") return "#9c27b0";
        return "#6c757d";
    };

    return (
        <div
            style={{
                position: "fixed",
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                backgroundColor: "rgba(0,0,0,0.7)",
                zIndex: 99999,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                backdropFilter: "blur(8px)",
            }}
        >
            <div
                style={{
                    width: "90%",
                    maxWidth: "1200px",
                    height: "80vh",
                    backgroundColor: "#fff",
                    borderRadius: "16px",
                    display: "flex",
                    overflow: "hidden",
                    boxShadow: "0 20px 60px rgba(0,0,0,0.3)",
                }}
            >
                {/* Left Sidebar - User List */}
                <div
                    style={{
                        width: "320px",
                        borderRight: "1px solid #e9ecef",
                        display: "flex",
                        flexDirection: "column",
                        backgroundColor: "#f8f9fa",
                    }}
                >
                    <div
                        style={{
                            padding: "20px",
                            borderBottom: "1px solid #e9ecef",
                            display: "flex",
                            justifyContent: "space-between",
                            alignItems: "center",
                        }}
                    >
                        <h5 style={{ margin: 0, fontWeight: 600 }}>Messages</h5>
                        <button
                            onClick={onClose}
                            style={{
                                background: "none",
                                border: "none",
                                cursor: "pointer",
                                padding: "4px",
                            }}
                        >
                            <X size={20} />
                        </button>
                    </div>

                    <div style={{ flex: 1, overflowY: "auto" }}>
                        {messages.map((user) => (
                            <div
                                key={user.id}
                                onClick={() => setSelectedUser(user)}
                                style={{
                                    padding: "15px 20px",
                                    cursor: "pointer",
                                    backgroundColor: selectedUser?.id === user.id ? "#fff" : "transparent",
                                    borderBottom: "1px solid #e9ecef",
                                    transition: "all 0.2s",
                                    position: "relative",
                                }}
                                onMouseEnter={(e) => {
                                    if (selectedUser?.id !== user.id) {
                                        e.currentTarget.style.backgroundColor = "#fff";
                                    }
                                }}
                                onMouseLeave={(e) => {
                                    if (selectedUser?.id !== user.id) {
                                        e.currentTarget.style.backgroundColor = "transparent";
                                    }
                                }}
                            >
                                <div style={{ display: "flex", gap: "12px" }}>
                                    <div style={{ position: "relative" }}>
                                        <img
                                            src={user.avatar}
                                            alt={user.name}
                                            style={{
                                                width: "48px",
                                                height: "48px",
                                                borderRadius: "50%",
                                                objectFit: "cover",
                                            }}
                                        />
                                        <div
                                            style={{
                                                position: "absolute",
                                                bottom: "2px",
                                                right: "2px",
                                                width: "12px",
                                                height: "12px",
                                                borderRadius: "50%",
                                                backgroundColor: getStatusColor(user.status),
                                                border: "2px solid #fff",
                                            }}
                                        />
                                    </div>
                                    <div style={{ flex: 1, minWidth: 0 }}>
                                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                                            <strong style={{ fontSize: "14px" }}>{user.name}</strong>
                                            <span style={{ fontSize: "11px", color: "#adb5bd" }}>{user.lastSeen}</span>
                                        </div>
                                        <div style={{ display: "flex", alignItems: "center", gap: "6px", marginTop: "4px" }}>
                                            <span
                                                style={{
                                                    fontSize: "10px",
                                                    padding: "2px 6px",
                                                    borderRadius: "4px",
                                                    backgroundColor: getSenderTypeColor(user.role),
                                                    color: "#fff",
                                                }}
                                            >
                                                {user.role}
                                            </span>
                                            {user.company && (
                                                <span style={{ fontSize: "11px", color: "#6c757d" }}>{user.company}</span>
                                            )}
                                        </div>
                                        <p
                                            style={{
                                                fontSize: "12px",
                                                color: "#6c757d",
                                                margin: "6px 0 0",
                                                whiteSpace: "nowrap",
                                                overflow: "hidden",
                                                textOverflow: "ellipsis",
                                            }}
                                        >
                                            {user.messages[user.messages.length - 1]?.text}
                                        </p>
                                    </div>
                                </div>
                                {user.unread > 0 && (
                                    <span
                                        style={{
                                            position: "absolute",
                                            right: "20px",
                                            top: "50%",
                                            transform: "translateY(-50%)",
                                            backgroundColor: "#ff3e43",
                                            color: "#fff",
                                            fontSize: "10px",
                                            fontWeight: "bold",
                                            padding: "2px 6px",
                                            borderRadius: "10px",
                                        }}
                                    >
                                        {user.unread}
                                    </span>
                                )}
                            </div>
                        ))}
                    </div>
                </div>

                {/* Right Side - Chat Area */}
                <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>
                    {/* Chat Header */}
                    <div
                        style={{
                            padding: "20px",
                            borderBottom: "1px solid #e9ecef",
                            display: "flex",
                            alignItems: "center",
                            gap: "12px",
                        }}
                    >
                        <img
                            src={selectedUser?.avatar}
                            alt={selectedUser?.name}
                            style={{
                                width: "40px",
                                height: "40px",
                                borderRadius: "50%",
                                objectFit: "cover",
                            }}
                        />
                        <div>
                            <h6 style={{ margin: 0, fontWeight: 600 }}>{selectedUser?.name}</h6>
                            <div style={{ display: "flex", gap: "8px", alignItems: "center" }}>
                                <span
                                    style={{
                                        fontSize: "11px",
                                        padding: "2px 8px",
                                        borderRadius: "4px",
                                        backgroundColor: getSenderTypeColor(selectedUser?.role),
                                        color: "#fff",
                                    }}
                                >
                                    {selectedUser?.role}
                                </span>
                                {selectedUser?.company && (
                                    <span style={{ fontSize: "11px", color: "#6c757d" }}>{selectedUser?.company}</span>
                                )}
                            </div>
                        </div>
                    </div>

                    {/* Messages Area */}
                    <div
                        style={{
                            flex: 1,
                            overflowY: "auto",
                            padding: "20px",
                            display: "flex",
                            flexDirection: "column",
                            gap: "12px",
                            backgroundColor: "#f8f9fa",
                        }}
                    >
                        {selectedUser?.messages.map((msg) => (
                            <div
                                key={msg.id}
                                style={{
                                    display: "flex",
                                    justifyContent: msg.isMe ? "flex-end" : "flex-start",
                                }}
                            >
                                <div
                                    style={{
                                        maxWidth: "70%",
                                        padding: "10px 14px",
                                        borderRadius: "12px",
                                        backgroundColor: msg.isMe ? "#ff3e43" : "#fff",
                                        color: msg.isMe ? "#fff" : "#212529",
                                        boxShadow: "0 1px 2px rgba(0,0,0,0.1)",
                                    }}
                                >
                                    <p style={{ margin: 0, fontSize: "14px" }}>{msg.text}</p>
                                    <span
                                        style={{
                                            fontSize: "10px",
                                            color: msg.isMe ? "rgba(255,255,255,0.7)" : "#adb5bd",
                                            display: "block",
                                            marginTop: "4px",
                                        }}
                                    >
                                        {msg.time}
                                    </span>
                                </div>
                            </div>
                        ))}
                    </div>

                    {/* Message Input */}
                    <div
                        style={{
                            padding: "20px",
                            borderTop: "1px solid #e9ecef",
                            display: "flex",
                            gap: "12px",
                            backgroundColor: "#fff",
                        }}
                    >
                        <input
                            type="text"
                            placeholder="Type your message..."
                            value={messageInput}
                            onChange={(e) => setMessageInput(e.target.value)}
                            onKeyPress={(e) => e.key === "Enter" && handleSendMessage()}
                            style={{
                                flex: 1,
                                padding: "10px 14px",
                                border: "1px solid #e9ecef",
                                borderRadius: "24px",
                                outline: "none",
                                fontSize: "14px",
                            }}
                        />
                        <button
                            onClick={handleSendMessage}
                            style={{
                                backgroundColor: "#ff3e43",
                                border: "none",
                                borderRadius: "50%",
                                width: "40px",
                                height: "40px",
                                display: "flex",
                                alignItems: "center",
                                justifyContent: "center",
                                cursor: "pointer",
                                transition: "background 0.2s",
                            }}
                            onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = "#e0353a")}
                            onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = "#ff3e43")}
                        >
                            <Send size={18} color="#fff" />
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

